package main

// Runs database migrations using golang-migrate.
//
// Usage:
//   go run ./cmd/migrate up       # apply all pending migrations
//   go run ./cmd/migrate down 1   # rollback the last migration
//   go run ./cmd/migrate version  # print current schema version
//
// In CI / production this is typically run as a Kubernetes Job before the
// rolling deployment of the API Deployment — see deploy/k8s for an example
// Job template.

import (
	"errors"
	"log"
	"os"
	"strconv"

	"github.com/golang-migrate/migrate/v4"
	_ "github.com/golang-migrate/migrate/v4/database/postgres"
	_ "github.com/golang-migrate/migrate/v4/source/file"

	"github.com/your-username/test-app/internal/config"
)

func main() {
	cfg := config.Load()
	if cfg.DatabaseURL == "" {
		log.Fatal("DATABASE_URL must be set to run migrations")
	}

	m, err := migrate.New("file://migrations", cfg.DatabaseURL)
	if err != nil {
		log.Fatalf("open migrations: %v", err)
	}
	defer func() {
		if srcErr, dbErr := m.Close(); srcErr != nil || dbErr != nil {
			log.Printf("close migrate: src=%v db=%v", srcErr, dbErr)
		}
	}()

	cmd := "up"
	if len(os.Args) > 1 {
		cmd = os.Args[1]
	}

	switch cmd {
	case "up":
		if err := m.Up(); err != nil && !errors.Is(err, migrate.ErrNoChange) {
			log.Fatalf("migrate up: %v", err)
		}
		log.Println("migrations applied")
	case "down":
		n := 1
		if len(os.Args) > 2 {
			var err error
			n, err = strconv.Atoi(os.Args[2])
			if err != nil {
				log.Fatalf("invalid step count: %v", err)
			}
		}
		if err := m.Steps(-n); err != nil {
			log.Fatalf("migrate down: %v", err)
		}
		log.Printf("rolled back %d migrations", n)
	case "version":
		v, dirty, err := m.Version()
		if err != nil {
			log.Fatalf("version: %v", err)
		}
		log.Printf("schema version: %d (dirty=%t)", v, dirty)
	default:
		log.Fatalf("unknown subcommand: %s (want up/down/version)", cmd)
	}
}

