package db

import (
	"time"

	gormPg "gorm.io/driver/postgres"
	"gorm.io/gorm"
)

func OpenGorm(dsn string) (*gorm.DB, error) {
	// GORM wraps the underlying *sql.DB; configure the pool explicitly rather
	// than relying on GORM's defaults (no pool configuration at all).
	db, err := gorm.Open(gormPg.Open(dsn), &gorm.Config{})
	if err != nil {
		return nil, err
	}
	sqlDB, err := db.DB()
	if err != nil {
		return nil, err
	}
	sqlDB.SetMaxOpenConns(25)
	sqlDB.SetMaxIdleConns(10)
	sqlDB.SetConnMaxLifetime(30 * time.Minute)
	return db, nil
}

internal/db/sql.go:
package db

import (
	"context"
	"errors"
	"fmt"
	"log"
	"time"

	_ "github.com/jackc/pgx/v5/stdlib"
	"database/sql"
)

// Open connects to the database and retries transient errors with exponential
// backoff (up to ~30s total). Kubernetes pods frequently come up before their
// database StatefulSet / managed instance accepts connections — without retry
// the API pod restarts and delays rollout.
//
// Pool sizing (25 open / 10 idle / 30m lifetime) matches Go's community
// consensus for a single-instance API talking to Postgres. Tune per your
// connection-limited deployment (e.g. pgbouncer transaction pooling).
func Open(dsn string) (*sql.DB, error) {
	// db: postgres
	conn, err := sql.Open("pgx", dsn)
	if err != nil {
		return nil, fmt.Errorf("sql.Open: %w", err)
	}
	conn.SetMaxOpenConns(25)
	conn.SetMaxIdleConns(10)
	conn.SetConnMaxLifetime(30 * time.Minute)

	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
	defer cancel()

	var lastErr error
	backoff := 200 * time.Millisecond
	for attempt := 1; attempt <= 6; attempt++ {
		if err := conn.PingContext(ctx); err == nil {
			return conn, nil
		} else {
			lastErr = err
			if errors.Is(err, context.DeadlineExceeded) || errors.Is(err, context.Canceled) {
				break
			}
			log.Printf("db: ping failed (attempt %d/6): %v — retrying in %s", attempt, err, backoff)
			select {
			case <-ctx.Done():
				return nil, fmt.Errorf("db: context cancelled while retrying: %w", ctx.Err())
			case <-time.After(backoff):
			}
			backoff *= 2
			if backoff > 5*time.Second {
				backoff = 5 * time.Second
			}
		}
	}
	return nil, fmt.Errorf("db: could not connect after retries: %w", lastErr)
}

