package handlers_test

import (
	"bytes"
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"testing"

	"github.com/gin-gonic/gin"
	"gorm.io/driver/sqlite"
	"gorm.io/gorm"

	"github.com/your-username/test-app/internal/handlers"
	"github.com/your-username/test-app/internal/models"
)

func setupPostDB(t *testing.T) *gorm.DB {
	t.Helper()
	db, err := gorm.Open(sqlite.Open(":memory:"), &gorm.Config{})
	if err != nil { t.Fatal(err) }
	if err := db.AutoMigrate(&models.Post{}); err != nil { t.Fatal(err) }
	return db
}

func TestPostHandler(t *testing.T) {
	gin.SetMode(gin.TestMode)
	db := setupPostDB(t)
	h := handlers.NewPostHandler(db)

	r := gin.New()
	r.GET("/posts", h.List)
	r.GET("/posts/:id", h.GetByID)
	r.POST("/posts", h.Create)
	r.PATCH("/posts/:id", h.Update)
	r.DELETE("/posts/:id", h.Delete)

	var createdID string

	t.Run("list empty", func(t *testing.T) {
		w := httptest.NewRecorder()
		r.ServeHTTP(w, httptest.NewRequest(http.MethodGet, "/posts", nil))
		if w.Code != http.StatusOK { t.Errorf("want 200 got %d: %s", w.Code, w.Body) }
	})

	t.Run("create", func(t *testing.T) {
		body, _ := json.Marshal(map[string]any{"title": "test", "body": "test", "published": true})
		req := httptest.NewRequest(http.MethodPost, "/posts", bytes.NewReader(body))
		req.Header.Set("Content-Type", "application/json")
		w := httptest.NewRecorder()
		r.ServeHTTP(w, req)
		if w.Code != http.StatusCreated { t.Errorf("want 201 got %d: %s", w.Code, w.Body) }
		var resp map[string]any
		_ = json.Unmarshal(w.Body.Bytes(), &resp)
		if id, ok := resp["id"].(string); ok { createdID = id }
	})

	t.Run("get by id", func(t *testing.T) {
		if createdID == "" { t.Skip("depends on create") }
		w := httptest.NewRecorder()
		r.ServeHTTP(w, httptest.NewRequest(http.MethodGet, "/posts/"+createdID, nil))
		if w.Code != http.StatusOK { t.Errorf("want 200 got %d", w.Code) }
	})

	t.Run("get not found", func(t *testing.T) {
		w := httptest.NewRecorder()
		r.ServeHTTP(w, httptest.NewRequest(http.MethodGet, "/posts/00000000-0000-0000-0000-000000000000", nil))
		if w.Code != http.StatusNotFound { t.Errorf("want 404 got %d", w.Code) }
	})

	t.Run("update", func(t *testing.T) {
		if createdID == "" { t.Skip("depends on create") }
		body, _ := json.Marshal(map[string]any{"title": "updated", "body": "updated", "published": true})
		req := httptest.NewRequest(http.MethodPatch, "/posts/"+createdID, bytes.NewReader(body))
		req.Header.Set("Content-Type", "application/json")
		w := httptest.NewRecorder()
		r.ServeHTTP(w, req)
		if w.Code != http.StatusOK { t.Errorf("want 200 got %d: %s", w.Code, w.Body) }
	})

	t.Run("delete", func(t *testing.T) {
		if createdID == "" { t.Skip("depends on create") }
		w := httptest.NewRecorder()
		r.ServeHTTP(w, httptest.NewRequest(http.MethodDelete, "/posts/"+createdID, nil))
		if w.Code != http.StatusNoContent { t.Errorf("want 204 got %d", w.Code) }
	})
}

