package handlers

import (
	"net/http"

	"github.com/gin-gonic/gin"
	"gorm.io/gorm"

	"github.com/your-username/test-app/internal/models"
)

type PostHandler struct{ db *gorm.DB }

func NewPostHandler(db *gorm.DB) *PostHandler { return &PostHandler{db: db} }

func (h *PostHandler) List(c *gin.Context) {
	var items []models.Post
	if err := h.db.Find(&items).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}
	c.JSON(http.StatusOK, items)
}

func (h *PostHandler) GetByID(c *gin.Context) {
	var item models.Post
	if err := h.db.First(&item, "id = ?", c.Param("id")).Error; err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "not found"})
		return
	}
	c.JSON(http.StatusOK, item)
}

func (h *PostHandler) Create(c *gin.Context) {
	var payload models.Post
	if err := c.ShouldBindJSON(&payload); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
