package server

import (
	"context"
	"log/slog"
	"net/http"
	"os"

	"github.com/gin-gonic/gin"

	"github.com/your-username/test-app/internal/config"
	"github.com/your-username/test-app/internal/db"
	"github.com/your-username/test-app/internal/cache"
	"github.com/your-username/test-app/internal/handlers"
)

type Server struct {
	cfg    *config.Config
	log    *slog.Logger
	srv    *http.Server
	engine *gin.Engine
}

func New(cfg *config.Config, log *slog.Logger) *Server {
	gin.SetMode(gin.ReleaseMode)
	r := gin.New()
	r.Use(recoverer(log), requestLog(log), rateLimit(), tracing(), auditLog(log))

	r.GET("/health", healthHandler)
	r.GET("/health", handleGetHealth)
	r.GET("/users", authRequired, handleGetUsers)
	r.POST("/users", authRequired, handlePostUsers)
	r.GET("/users/:id", authRequired, handleGetUsersById)
	r.DELETE("/users/:id", authRequired, handleDeleteUsersById)
	gormDB, err := db.OpenGorm(cfg.DatabaseURL)
	if err != nil {
		log.Error("gorm open", "err", err)
		os.Exit(1)
	}
	userH := handlers.NewUserHandler(gormDB)
	postH := handlers.NewPostHandler(gormDB)
	r.GET("/users", userH.List)
	r.GET("/users/:id", userH.GetByID)
	r.POST("/users", userH.Create)
	r.PATCH("/users/:id", userH.Update)
	r.DELETE("/users/:id", userH.Delete)
	r.GET("/posts", postH.List)
	r.GET("/posts/:id", postH.GetByID)
	r.POST("/posts", postH.Create)
	r.PATCH("/posts/:id", postH.Update)
	r.DELETE("/posts/:id", postH.Delete)

	return &Server{cfg: cfg, log: log, engine: r, srv: &http.Server{
		Addr:    ":" + cfg.Port,
		Handler: r,
	}}
}

func (s *Server) Run() error {
	s.log.Info("listening", "addr", s.srv.Addr)
	return s.srv.ListenAndServe()
}

func (s *Server) Shutdown(ctx context.Context) error { return s.srv.Shutdown(ctx) }
func (s *Server) Handler() http.Handler     { return s.engine }

func handleGetHealth(c *gin.Context) {
	c.JSON(200, gin.H{"ok": true, "op": "GET /health"})
}

func handleGetUsers(c *gin.Context) {
	c.JSON(200, gin.H{"ok": true, "op": "GET /users"})
}

func handlePostUsers(c *gin.Context) {
	c.JSON(200, gin.H{"ok": true, "op": "POST /users"})
}

func handleGetUsersById(c *gin.Context) {
